// CreateOrder handler
func (s *OrderServiceServer) CreateOrder(ctx context.Context, req *CreateOrderRequest) (*OrderResponse, error) {
	logRequest(ctx, "OrderService.CreateOrder")

	if req.UserId == "" {
		return nil, status.Error(codes.InvalidArgument, "user_id is required")
	}
	if len(req.Items) == 0 {
		return nil, status.Error(codes.InvalidArgument, "at least one item is required")
	}

	// Verify user exists
	s.userStore.mu.RLock()
	_, userExists := s.userStore.users[req.UserId]
	s.userStore.mu.RUnlock()
	if !userExists {
		return nil, status.Errorf(codes.FailedPrecondition, "user %s not found", req.UserId)
	}

	s.store.mu.Lock()
	defer s.store.mu.Unlock()

	id := fmt.Sprintf("order-%d", len(s.store.orders)+1)
	var total float64
	var items []*OrderItem
	for _, item := range req.Items {
		total += float64(item.Quantity) * item.Price
		items = append(items, &OrderItem{
			ProductID: item.ProductId,
			Name:      item.Name,
			Quantity:  item.Quantity,
			Price:     item.Price,
		})
	}

	order := &Order{
		ID:        id,
		UserID:    req.UserId,
		Items:     items,
		Total:     total,
		Status:    "pending",
		CreatedAt: time.Now(),
	}
	s.store.orders[id] = order

	log.Printf("Created order: %s for user %s (total: $%.2f)", order.ID, order.UserID, order.Total)
	return orderToResponse(order), nil
}

